import (
	"sort"
)

func solve(nums []int64, k int64) int64 {
	if len(nums) == 1 {
		return 0
	}

	// Sort the array to easily find min and max in any subarray
	sort.Int64s(nums)

	// Initialize variables
	n := len(nums)
	minRemove := n - 1 // Maximum possible removals

	// Try all possible subarrays
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			// Check if the subarray from i to j is balanced
			if nums[j] <= nums[i]*k {
				// Calculate the number of elements to remove
				remove := n - (j - i + 1)
				if remove < minRemove {
					minRemove = remove
				}
			}
		}
	}

	return int64(minRemove)
}
